INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bf1f4ba6-9f51-443c-96c5-5db0031e3196',
  '00000000-0000-0000-0000-000000000001',
  $escape$CSS Modules Bundle Optimization — Taming PurgeCSS, Font Subsetting, and Icon Strategy$escape$,
  $escape$CSS Modules' hashed class names break PurgeCSS's default string-matching extractor. When scanning JS for `.button`, it finds `styles.button` — dot-property access isn't matched, so valid classes get purged in production. Fix it with a custom extractor that also captures property names from object access patterns. For font subsetting, declare `@font-face` with `unicode-range` directly inside your `.module.css` files — each module loads only the glyph subset it references, preventing full-font payloads on unvisited routes. For icons, avoid barrel-importing an entire icon library into a shared module. Instead, use `composes: iconBase from './icons.module.css'` to keep icon CSS colocated with its usage and tree-shakeable at build time. In Vite, pair this with `build.cssCodeSplit: true` so each route's compiled CSS Modules output lands in a separate chunk. Lazy-loaded routes then ship zero font or icon CSS until actually visited.$escape$,
  $escape$// postcss.config.js — custom extractor that handles CSS Modules object-property access
module.exports = {
  plugins: [
    require('@fullhuman/postcss-purgecss')({
      content: ['./src/**/*.{tsx,ts,jsx,js}'],
      defaultExtractor(content) {
        // Default extractor misses `styles.button` — capture property names too
        const broad = content.match(/[A-Za-z0-9_-]+/g) ?? [];
        const props = content.match(/(?<=\.)[A-Za-z0-9_]+/g) ?? [];
        return [...new Set([...broad, ...props])];
      },
    }),
  ],
};$escape$,
  $escape$javascript$escape$,
